{
  "summary": "The paper systematically investigates Language Model (LM) architectures, specifically PrefixLM and CausalLM variants, for Machine Translation, comparing their scaling properties and performance against traditional Encoder-Decoder (EncDec) models across bilingual, multilingual, and zero-shot tasks. It demonstrates that while architectural differences narrow at scale, PrefixLM variants significantly improve zero-shot translation by reducing off-target translations, often outperforming EncDec in BLEU. The study provides valuable insights and guidance for selecting NMT architectures based on task requirements, highlighting PrefixLM's promise for large-scale multilingual models with zero-shot capabilities.",
  "strengths": [
    {
      "point": "Systematic and Comprehensive Study of LM Architectures for NMT",
      "evidence": "The paper provides a comprehensive and systematic study of various LM architectural design choices and their impact on translation performance across different scales, data conditions, and tasks."
    },
    {
      "point": "Valuable Insights into Scaling Behavior and Architectural Trade-offs",
      "evidence": "It reveals how architectural differences matter at smaller scales but diminish at larger scales, and how the way parameters are added (depth vs. width) impacts translation. The findings suggest that for large-scale multilingual models with a focus on zero-shot transfer, LMs (specifically PrefixLM) are a promising direction, while EncDec remains suitable for major language pairs or smaller on-device models."
    },
    {
      "point": "Demonstrated Superiority of PrefixLM for Zero-shot Translation",
      "evidence": "It demonstrates that PrefixLM architectures, with full source visibility, significantly improve zero-shot translation performance by reducing off-target translations, often outperforming EncDec in BLEU."
    },
    {
      "point": "Detailed Comparative Analysis between LM and EncDec Architectures",
      "evidence": "The work offers a detailed comparison of LM and EncDec architectures in terms of translation quality, scaling properties, and computational efficiency."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited Novelty in Proposed LM Variants, being adaptations of existing designs",
      "evidence": "The proposed LM variants themselves (PrefixLM, CausalLM, and their minor extensions like TopOnly or TgtOnly) are adaptations of existing designs rather than fundamentally new architectural innovations."
    },
    {
      "point": "Insufficient Justification and Analysis for Parameter Tying in PrefixLM+TopOnly",
      "evidence": "The 'PrefixLM + TopOnly' variant explicitly ties encoder-decoder parameters. The paper should explicitly justify this parameter tying and analyze its impact on effective model capacity and parameter efficiency when comparing against a full EncDec baseline."
    },
    {
      "point": "Incomplete Exploration of Model Scaling Dimensions",
      "evidence": "It's unclear if other critical model dimensions, such as embedding size, number of attention heads, or overall hidden state size, were also scaled proportionally or kept fixed. Limiting scaling to just depth and FF-dimension might not capture a comprehensive understanding of scaling laws."
    },
    {
      "point": "Lack of Specificity for EncDec Baseline and Reproducibility Details",
      "evidence": "Specific details regarding the EncDec architecture, its hyper-parameters, whether it's a SOTA variant, and how it was optimized for each task... are missing, making it difficult to fully assess the fairness and strength of the comparative analysis. The summary lacks crucial training details essential for reproducing the results."
    },
    {
      "point": "Inadequate Explanation for Divergent PPL and BLEU in Zero-shot Scenarios",
      "evidence": "EncDec maintains better fitting ability (lower PPL) in zero-shot scenarios' while 'PrefixLM variants show significant improvement on zero-shot directions... surpassing EncDec in BLEU.' This divergent outcome... requires deeper analysis and explanation beyond merely stating the findings."
    },
    {
      "point": "Absence of Human Evaluation for Zero-shot Translation Claims",
      "evidence": "For zero-shot translation, where automated metrics like BLEU can be less reliable indicators of quality... the absence of human evaluation... is a notable limitation."
    },
    {
      "point": "Lack of Comparison with Fine-tuning Large Pre-trained LMs for NMT",
      "evidence": "It does not explicitly mention comparison against or integration with the prevalent paradigm of fine-tuning very large *pre-trained* LMs (e.g., models based on GPT, Llama, or even encoder-only models like BERT adapted for NMT) on translation tasks, which represents a major direction in modern NMT research and transfer learning."
    }
  ],
  "questions": [
    {
      "question": "Could the paper provide a clearer justification for the parameter tying in 'PrefixLM + TopOnly' and analyze its specific impact on model capacity and efficiency in comparison to untied EncDec models?",
      "motivation": "Understanding this design choice is crucial for a complete architectural comparison and evaluating its implications for resource efficiency and performance."
    },
    {
      "question": "Beyond depth and feed-forward dimension, were other critical model dimensions (e.g., embedding size, attention heads) scaled or kept constant, and how might a multi-dimensional scaling analysis further refine the understanding of observed scaling laws?",
      "motivation": "A more comprehensive scaling study across various architectural dimensions would provide deeper insights into optimal model growth strategies."
    },
    {
      "question": "Given the observed divergence between PPL and BLEU in zero-shot scenarios (EncDec lower PPL, PrefixLM higher BLEU), what underlying mechanisms explain this trade-off, and how does 'fitting ability' relate differently to translation quality in this context?",
      "motivation": "A deeper analysis of this seemingly contradictory result is essential for understanding the intrinsic behaviors of these architectures in challenging zero-shot settings."
    },
    {
      "question": "How do the findings of this systematic architectural comparison integrate with or compare against the performance of very large, pre-trained LMs (e.g., GPT, Llama) fine-tuned for NMT, which represents a dominant paradigm in current research?",
      "motivation": "Placing the work in the context of state-of-the-art pre-trained models is critical for assessing its relevance and guiding future research directions in NMT."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "accept",
    "confidence": 4
  }
}
